import { requestStructuredMode } from './mode-api.js';
import { buildResonancePrompt } from './prompt-schemas.js';
import { bindGuideLayer, renderTextLayer, setGuideOpen } from './guide-layer.js';
import { buildResonanceFallback } from './mode-prose.js';

const RESONANCE_MODES = ['harmony', 'tension', 'mirror', 'transformation'];
const HUMAN_ID = 'resonance-human';
const NARRATION_ID = 'resonance-narration';

export function createResonanceMode(ctx) {
  let current = null;
  let activeMode = 'harmony';

  function collectRef(ref) {
    const name = ctx.getEntryName(ref.cat, ref.entry);
    return {
      cat: ref.cat,
      label: ctx.CAT_META[ref.cat]?.label || ref.cat,
      name,
      glyph: ctx.getGlyph(name, ref.cat),
      color: ctx.getColorForEntry(name, ref.cat),
      entry: ref.entry
    };
  }

  function compare(a, b) {
    const shared = [];
    const tensions = [];
    ctx.DISPLAY_FIELD_ORDER.forEach(key => {
      if (!a.entry[key] || !b.entry[key]) return;
      const av = ctx.splitValues(a.entry[key]);
      const bv = ctx.splitValues(b.entry[key]);
      const common = av.filter(item => bv.some(other => ctx.normalizeName(item) === ctx.normalizeName(other)));
      if (common.length) shared.push({ field: ctx.CAT_META[key]?.label || key, values: common });
      else if (key !== a.cat && key !== b.cat) tensions.push({ field: ctx.CAT_META[key]?.label || key, a: av.slice(0, 2).join('; '), b: bv.slice(0, 2).join('; ') });
    });
    const bridges = shared.slice(0, 5).map(row => `${row.field}: ${row.values.join('; ')}`);
    return { shared_fields: shared, tensions: tensions.slice(0, 8), frictions: tensions.slice(0, 8), bridges, hidden_bridges: bridges };
  }

  function fallback(payload) {
    return buildResonanceFallback(payload, activeMode);
  }

  function normalizeResult(result) {
    return {
      ...result,
      frictions: result.frictions || result.tensions || [],
      hidden_bridges: result.hidden_bridges || result.bridges || [],
      display_text: result.display_text || result.short_reading || '',
      guide_text: result.guide_text || result.deep_reading || 'The human relationship reading is pending for this chamber.',
      narration_text: result.narration_text || result.audio_text || 'The narration transcript is pending for this chamber.',
      speech_aliases: result.speech_aliases || {}
    };
  }

  function renderLoading(payload) {
    const overlay = document.getElementById('cardOverlay');
    overlay.innerHTML = `<div class="mode-chamber resonance-chamber">
      <button class="card-close-btn mode-close" data-mode-close>X</button>
      <div class="mode-kicker">RESONANCE CHAMBER</div>
      <div class="resonance-presences">
        <div class="presence" style="--c:${payload.a.color}"><div>${payload.a.glyph}</div><span>${ctx.escapeHTML(payload.a.name)}</span></div>
        <div class="resonance-bridge"></div>
        <div class="presence" style="--c:${payload.b.color}"><div>${payload.b.glyph}</div><span>${ctx.escapeHTML(payload.b.name)}</span></div>
      </div>
      <div class="ritual-loader"><span></span><span></span><span></span></div>
      <div class="mode-copy">Aligning fields, tensions, and hidden bridges...</div>
    </div>`;
    overlay.classList.add('open');
    bindCommon();
  }

  function renderLocked(result) {
    const overlay = document.getElementById('cardOverlay');
    overlay.innerHTML = `<div class="mode-chamber resonance-chamber">
      <button class="card-close-btn mode-close" data-mode-close>X</button>
      <div class="mode-kicker">INITIATE GATE</div>
      <div class="mode-title">The chamber requires more charge.</div>
      <div class="mode-copy">Your ${ctx.escapeHTML(result.gate.plan)} resonance allotment is complete. Create a free account for daily encounters; Initiate unlocks narration, saved sessions, and unlimited resonance.</div>
      <button class="mode-btn-primary" data-mode-upgrade>CREATE FREE ACCOUNT</button>
    </div>`;
    overlay.classList.add('open');
    bindCommon();
  }

  function renderResult(payload, result) {
    result = normalizeResult(result);
    const overlay = document.getElementById('cardOverlay');
    const modes = RESONANCE_MODES.map(mode => `<button class="mode-chip ${mode === activeMode ? 'active' : ''}" data-res-mode="${mode}">${mode}</button>`).join('');
    const shared = (result.shared_fields || []).slice(0, 8).map(row => `<div class="mode-field"><span>${ctx.escapeHTML(row.field)}</span><b>${ctx.escapeHTML((row.values || []).join('; '))}</b></div>`).join('');
    const tensions = (result.frictions || []).slice(0, 6).map(row => `<div class="mode-field tension"><span>${ctx.escapeHTML(row.field)}</span><b>${ctx.escapeHTML(row.left || row.a || '')} / ${ctx.escapeHTML(row.right || row.b || '')}</b></div>`).join('');
    const bridges = (result.hidden_bridges || []).map(item => `<span>${ctx.escapeHTML(item)}</span>`).join('');
    overlay.innerHTML = `<div class="mode-chamber resonance-chamber">
      <button class="card-close-btn mode-close" data-mode-close>X</button>
      <div class="mode-kicker">RESONANCE CHAMBER</div>
      <div class="resonance-presences">
        <div class="presence" style="--c:${payload.a.color}"><div>${payload.a.glyph}</div><span>${ctx.escapeHTML(payload.a.name)}</span></div>
        <div class="resonance-bridge active"></div>
        <div class="presence" style="--c:${payload.b.color}"><div>${payload.b.glyph}</div><span>${ctx.escapeHTML(payload.b.name)}</span></div>
      </div>
      <div class="mode-tone-row">${modes}</div>
      <div class="mode-grid">${shared || '<div class="mode-copy">No direct shared fields surfaced.</div>'}</div>
      <div class="mode-grid tension-grid">${tensions}</div>
      <div class="mode-motifs">${bridges}</div>
      <div class="layer-caption">Primary Occult Resonance</div>
      <div class="mode-reading occult-display">${ctx.escapeHTML(result.display_text || '').replace(/\n/g, '<br><br>')}</div>
      ${renderTextLayer({ id: HUMAN_ID, label: 'Human Reading - What this means in human terms', text: result.guide_text, open: true, variant: 'human' })}
      ${renderTextLayer({ id: NARRATION_ID, label: 'Narration Transcript', text: result.narration_text, open: true, variant: 'narration' })}
      <div class="mode-actions">
        <button class="mode-btn-primary" data-mode-audio>PLAY NARRATION</button>
        <button class="mode-btn" data-mode-copy>COPY</button>
      </div>
      <div class="mode-quota">${formatGate(result.gate)}</div>
    </div>`;
    overlay.classList.add('open');
    bindCommon(result.narration_text, result.speech_aliases);
  }

  function formatGate(gate) {
    if (!gate) return '';
    if (gate.plan === 'admin') return 'Admin test mode / resonance unsealed';
    if (gate.remaining === 'unlimited') return 'Initiate access / unlimited resonance';
    return `${gate.remaining} resonance session${gate.remaining === 1 ? '' : 's'} remaining for ${gate.plan}`;
  }

  function bindCommon(audioText = '', aliases = {}) {
    const overlay = document.getElementById('cardOverlay');
    bindGuideLayer(overlay);
    overlay.querySelector('[data-mode-close]')?.addEventListener('click', ctx.closeOverlay);
    overlay.querySelector('[data-mode-upgrade]')?.addEventListener('click', ctx.modeUsage.upgrade);
    overlay.querySelector('[data-mode-audio]')?.addEventListener('click', () => {
      setGuideOpen(overlay, HUMAN_ID, true);
      setGuideOpen(overlay, NARRATION_ID, true);
      ctx.modeAudio.speak(audioText, 'RESONANCE', { aliases });
    });
    overlay.querySelector('[data-mode-copy]')?.addEventListener('click', () => {
      const copyText = [
        overlay.querySelector('.occult-display')?.textContent || '',
        overlay.querySelector(`[data-guide-body="${HUMAN_ID}"]`)?.textContent || '',
        overlay.querySelector(`[data-guide-body="${NARRATION_ID}"]`)?.textContent || ''
      ].filter(Boolean).join('\n\n');
      navigator.clipboard?.writeText(copyText || audioText || overlay.textContent || '');
      ctx.setStatus('RESONANCE COPIED');
    });
    overlay.querySelectorAll('[data-res-mode]').forEach(btn => {
      btn.addEventListener('click', () => {
        activeMode = btn.dataset.resMode || 'harmony';
        if (current) open(current.aRef, current.bRef, activeMode);
      });
    });
  }

  async function open(aRef, bRef, mode = activeMode) {
    activeMode = mode;
    current = { aRef, bRef };
    const a = collectRef(aRef);
    const b = collectRef(bRef);
    const relation = compare(a, b);
    const payload = { a, b, ...relation, mode: activeMode };
    renderLoading(payload);
    const result = await requestStructuredMode({
      feature: 'resonance',
      prompt: buildResonancePrompt(payload, activeMode),
      usage: ctx.modeUsage,
      fallback: () => fallback(payload),
      setStatus: ctx.setStatus
    });
    if (result.locked) renderLocked(result);
    else renderResult(payload, result);
  }

  return { open };
}
