import { normalizeSpeechText } from './speech-normalize.js';

export function createModeAudio({ setStatus } = {}) {
  let utterance = null;
  let lastText = '';

  function stop() {
    if ('speechSynthesis' in window) speechSynthesis.cancel();
    utterance = null;
  }

  function speak(text, label = 'NARRATION', options = {}) {
    if (!text || !('speechSynthesis' in window)) {
      setStatus?.('NARRATION UNAVAILABLE');
      return;
    }
    const cleanText = normalizeSpeechText(text, options.aliases || {});
    if (speechSynthesis.speaking && lastText === cleanText && !speechSynthesis.paused) {
      speechSynthesis.pause();
      setStatus?.(`${label} PAUSED`);
      return;
    }
    if (speechSynthesis.paused && lastText === cleanText) {
      speechSynthesis.resume();
      setStatus?.(`${label} RESUMED`);
      return;
    }
    stop();
    utterance = new SpeechSynthesisUtterance(cleanText);
    utterance.lang = 'en-US';
    utterance.rate = 0.88;
    utterance.pitch = 1.03;
    const voices = speechSynthesis.getVoices?.() || [];
    utterance.voice =
      voices.find(v => /en-US/i.test(v.lang) && /Google|Female|Jenny|Aria|Samantha|Zira/i.test(v.name)) ||
      voices.find(v => /en-US/i.test(v.lang)) ||
      null;
    lastText = cleanText;
    speechSynthesis.speak(utterance);
    setStatus?.(`${label} TRANSMITTING`);
  }

  return { speak, stop };
}
