import { createModeAudio } from './mode-audio.js';
import { createModeUsage } from './mode-usage.js';
import { createSynthesisMode } from './synthesis-mode.js';
import { createResonanceMode } from './resonance-mode.js';
import { createStreamMode } from './stream-mode.js';

export function createRitualModes(context) {
  const modeUsage = createModeUsage({ setStatus: context.setStatus });
  const modeAudio = createModeAudio({ setStatus: context.setStatus });
  const ctx = { ...context, modeUsage, modeAudio };
  return {
    usage: modeUsage,
    audio: modeAudio,
    synthesis: createSynthesisMode(ctx),
    resonance: createResonanceMode(ctx),
    stream: createStreamMode(ctx)
  };
}
